={{ (function() {
  const opportunities = $('Fetch Proposal Follow Up 7 Opportunities').all();
  if (!opportunities.length) return "SELECT Id, WhatId, Subject, ActivityDate, CreatedDate FROM Task WHERE Id = null LIMIT 1";
  const esc = (s) => String(s).replace(/'/g, "\\'");
  const subjects = [
    'Proposal Follow Up - Confirm Proposal Sent',
    'Proposal Follow Up - Call #1',
    'Proposal Follow Up - Email #1',
    'Proposal Follow Up - Call #2',
    'Proposal Follow Up - Email #2',
    'Proposal Follow Up - Status Review'
  ];
  const subjectList = subjects.map((s) => "'" + esc(s) + "'").join(', ');
  const opportunityIds = opportunities.map((o) => "'" + esc(o.json.Id) + "'").join(', ');
  return "SELECT Id, WhatId, Subject, ActivityDate, CreatedDate FROM Task WHERE WhatId IN (" + opportunityIds + ") AND Subject IN (" + subjectList + ") LIMIT 1000";
})() }}

parameters.jsCode:
const STEPS = [
  {
    key: 'Day_0',
    offsetDays: 0,
    subject: 'Proposal Follow Up - Confirm Proposal Sent',
    action: 'Confirm the proposal was sent and a follow-up meeting was requested.',
    guidelines: 'Confirm the personalized proposal email, proposal attachment or link, Proposal Sent Date, and proposed review date.'
  },
  {
    key: 'Day_1',
    offsetDays: 1,
    subject: 'Proposal Follow Up - Call #1',
    action: 'Call to confirm proposal receipt.',
    guidelines: 'Confirm that the prospect received the proposal, ask what questions they have, and try to schedule a proposal review if one is not already booked.'
  },
  {
    key: 'Day_2',
    offsetDays: 2,
    subject: 'Proposal Follow Up - Email #1',
    action: 'Send proposal follow-up email #1.',
    guidelines: 'Ask whether they had a chance to review the proposal, offer to walk through it with Example User or Io, and confirm any legal, technical, or stakeholder questions.'
  },
  {
    key: 'Day_3',
    offsetDays: 3,
    subject: 'Proposal Follow Up - Call #2',
    action: 'Complete the proposal review and objection-check call.',
    guidelines: 'Discuss questions, the decision process, stakeholders, legal or technical review needs, and whether they want to move to agreement.'
  },
  {
    key: 'Day_5',
    offsetDays: 5,
    subject: 'Proposal Follow Up - Email #2',
    action: 'Send proposal follow-up email #2 with a next-step call to action.',
    guidelines: 'Keep it concise. Ask whether they are ready for contract review, need a proposal review meeting, or need changes or clarification.'
  },
  {
    key: 'Day_7',
    offsetDays: 7,
    subject: 'Proposal Follow Up - Status Review',
    action: 'Review the Opportunity\u2019s Proposal follow-up status and choose the next step.',
    guidelines: 'Move to Contract if agreement or contract review is requested; restart another 7-day Proposal Follow-Up Sequence if active review continues; set a dated Follow-Up Date; or move to Closed Lost if no viable path remains.'
  }
];

const DAY0_SUBJECT = 'Proposal Follow Up - Confirm Proposal Sent';
const tz = 'America/Los_Angeles';
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });

function addDays(dateStr, days) {
  const [y, m, d] = dateStr.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d + days));
  return dt.toISOString().slice(0, 10);
}

function toW11DateTime(dateStr) {
  const [y, m, d] = dateStr.split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d, 20, 0, 0)).toISOString();
}

function buildStepResult(opportunity, step, anchorDate) {
  const opportunityId = String(opportunity.Id || '');
  const stepIndex = STEPS.findIndex((s) => s.key === step.key);
  const isFinalStep = step.key === 'Day_7';
  const effectiveAnchor = anchorDate || todayStr;
  const isDay0Bootstrap = step.offsetDays === 0 && !anchorDate;
  const rawDueDateStr = isDay0Bootstrap ? todayStr : addDays(effectiveAnchor, step.offsetDays);
  const needsW11Gate = !isDay0Bootstrap;
  let nextFollowUpRawDateStr = '';
  if (!isFinalStep) {
    const nextStep = STEPS[stepIndex + 1];
    if (nextStep) {
      nextFollowUpRawDateStr = addDays(effectiveAnchor, nextStep.offsetDays);
    }
  }
  return {
    json: {
      opportunityId,
      sequenceKey: opportunityId + '_ProposalFollowUp7',
      opportunityName: String(opportunity.Name || ''),
      opportunityOwnerId: String(opportunity.OwnerId || ''),
      anchorDate: effectiveAnchor,
      stepKey: step.key,
      stepIndex,
      taskSubject: step.subject,
      taskAction: step.action,
      taskGuidelines: step.guidelines,
      isFinalStep,
      needsW11Gate,
      rawDueDateStr,
      w11DueDateTime: toW11DateTime(rawDueDateStr),
      nextFollowUpRawDateStr,
      w11NextDateTime: nextFollowUpRawDateStr ? toW11DateTime(nextFollowUpRawDateStr) : '',
      w11Timezone: tz,
      todayStr
    }
  };
}

const tasksByOpportunity = {};
const day0AnchorByOpportunity = {};

for (const t of $('Fetch Proposal Sequence Tasks - Opportunities').all()) {
  const what = String(t.json.WhatId || '');
  const subj = String(t.json.Subject || '');
  if (!what || !subj) continue;
  if (!tasksByOpportunity[what]) tasksByOpportunity[what] = new Set();
  tasksByOpportunity[what].add(subj);

  if (subj === DAY0_SUBJECT) {
    const activityDate = String(t.json.ActivityDate || '').slice(0, 10);
    const createdDate = String(t.json.CreatedDate || '').slice(0, 10);
    const anchor = activityDate || createdDate;
    if (anchor && (!day0AnchorByOpportunity[what] || anchor < day0AnchorByOpportunity[what])) {
      day0AnchorByOpportunity[what] = anchor;
    }
  }
}

const results = [];

for (const item of $('Fetch Proposal Follow Up 7 Opportunities').all()) {
  const opportunity = item.json;
  const opportunityId = String(opportunity.Id || '');
  if (!opportunityId) continue;

  // Only Opportunities whose Engagement Status picklist is currently
  // "Proposal Follow Up (7)" remain eligible for this sequence.
  // Closed Opportunities are excluded by the SOQL filter.
  const existingSubjects = tasksByOpportunity[opportunityId] || new Set();
  const anchorDate = day0AnchorByOpportunity[opportunityId] || null;
  const stepsToCreate = [];

  if (!anchorDate) {
    if (!existingSubjects.has(DAY0_SUBJECT)) {
      stepsToCreate.push(STEPS[0]);
    }
  } else {
    for (let i = 1; i < STEPS.length; i++) {
      const step = STEPS[i];
      if (existingSubjects.has(step.subject)) continue;
      stepsToCreate.push(step);
      break;
    }
  }

  for (const step of stepsToCreate) {
    results.push(buildStepResult(opportunity, step, anchorDate));
  }
}

return results;

const preItems = $('Determine Proposal Follow Up 7 Sequence Step').all();
const results = [];

for (const w11Item of $input.all()) {
  const pi = w11Item.pairedItem?.item;
  if (pi === undefined || pi === null) continue;

  const ctx = preItems[pi]?.json;
  if (!ctx || !ctx.opportunityId) continue;

  if (ctx.needsW11Gate !== true) {
    results.push({ json: { ...ctx, adjustedDueDateStr: ctx.rawDueDateStr } });
    continue;
  }

  const w11 = w11Item.json || {};
  let adjustedDueDateStr = null;
  if (w11.isBusinessDay === true) {
    adjustedDueDateStr = String(w11.localDate || w11.nextBusinessDay || '').substring(0, 10);
  } else {
    adjustedDueDateStr = String(w11.nextBusinessDay || '').substring(0, 10);
  }
  if (!adjustedDueDateStr || adjustedDueDateStr.length < 8) continue;
  if (adjustedDueDateStr > ctx.todayStr) continue;

  results.push({ json: { ...ctx, adjustedDueDateStr } });
}

return results;

parameters.query:
={{ (function() {
  const items = $('Apply W11 - Confirm Proposal Task Due').all();
  if (!items.length) return "SELECT Id, WhatId, Subject FROM Task WHERE Id = null LIMIT 1";
  const esc = (s) => String(s).replace(/'/g, "\\'");
  const conditions = items.map((i) => "(WhatId = '" + esc(i.json.opportunityId) + "' AND Subject = '" + esc(i.json.taskSubject) + "')").join(' OR ');
  return "SELECT Id, WhatId, Subject FROM Task WHERE " + conditions + " LIMIT " + (items.length + 10);
})() }}

