const existing = new Set();
for (const t of $('Check Existing Proposal Opportunity Tasks').all()) {
  const what = String(t.json.WhatId || '');
  const subj = String(t.json.Subject || '');
  if (!what || !subj) continue;
  existing.add(what + '|' + subj);
}

const results = [];
for (const item of $('Apply W11 - Confirm Proposal Task Due').all()) {
  const d = item.json;
  const key = d.opportunityId + '|' + d.taskSubject;
  results.push({ json: { ...d, taskExists: existing.has(key) } });
}
return results;

const normalizeItems = $('Normalize Proposal Task Existence').all();
const results = [];
for (const item of $input.all()) {
  const pi = item.pairedItem?.item;
  if (pi === undefined || pi === null) continue;
  const ctx = normalizeItems[pi]?.json;
  if (!ctx || !ctx.opportunityId || ctx.taskExists === true) continue;
  results.push({ json: { ...ctx } });
}
return results;

const preItems = $('Recover Proposal Context After Create').all();
const results = [];

for (const w11Item of $input.all()) {
  const pi = w11Item.pairedItem?.item;
  if (pi === undefined || pi === null) continue;

  const ctx = preItems[pi]?.json;
  if (!ctx || !ctx.opportunityId) continue;

  const w11 = w11Item.json || {};
  let nextDueDateStr = null;
  if (w11.isBusinessDay === true) {
    nextDueDateStr = String(w11.localDate || w11.nextBusinessDay || '').substring(0, 10);
  } else {
    nextDueDateStr = String(w11.nextBusinessDay || '').substring(0, 10);
  }
  if (!nextDueDateStr || nextDueDateStr.length < 8) {
    results.push({ json: { ...ctx, nextDueDateStr: ctx.nextFollowUpRawDateStr } });
    continue;
  }

  results.push({ json: { ...ctx, nextDueDateStr } });
}

return results;
